{"inp":{"code":"# Ajustar margens e formatar indicadores percentuais e NaN
import math

for indicador in indicators:
    # Formatar percentuais com 2 decimais
    if indicador['indicator'] in ['Marg. Bruta', 'Marg. EBIT', 'Marg. Líquida', 'EBIT / Ativo', 'ROIC', 'ROE']:
        indicador['value'] = round(indicador['value'], 2)
    # Ajustar NaN para None
    if isinstance(indicador['value'], float) and math.isnan(indicador['value']):
        indicador['value'] = None

indicators.sort(key=lambda x: x['indicator'])

import json
json.dumps({"indicators": indicators})"}}
